  ('fire-eq-tech-moex-02341', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「出口標示燈及避難方向指示燈認可基準」之規定，下列敘述何者錯誤？', '["內置型引導燈具緊急電源時間應維持90分鐘以上", "燈具配線與電源側電線之連接點溫度上升變化應在35℃以下", "出口標示燈係以綠色為底，用白色表示「緊急出口」字樣", "外置型引導燈具使用螢光燈時，其緊急電源回路應有保險絲等保護裝置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02342', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「複合用途建築物判斷基準」之規定，複合用途建築物中，甲類場所樓地板面積合計小於該建築 物總樓地板面積百分之多少，視為「各類場所消防安全設備設置標準」第12條第5款第2目之複合 用途建築物？', '["百分之十", "百分之十五", "百分之二十", "百分之二十五"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02343', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「原有合法建築物防火避難設施及消防設備改善辦法」之規定，避難層之出入口應有一處以上之 出入口寬度不得小於X公分，高度不得低於Y公分，請問前述X，Y為何？', '["90，150", "60，180", "90，180", "60，150"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02344', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」之規定，有關避難器具外觀檢查之下降空地應有 寬多少公分以上之避難上有效通路，通往廣場、道路？', '["30公分", "60公分", "90公分", "100公分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02345', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」之規定，下列有關室外消防栓設備綜合檢查敘述， 何者錯誤？', '["檢查方法中，測量瞄子直線放水之壓力時，將壓力表之進水口，放置於瞄子前端瞄子口徑的三分 之一距離處，讀取壓力表的指示值", "檢查方法中，選擇配管上最遠最高處之二具室外消防栓做放水試驗", "判定方法中，放水壓力應在2.5 kgf/cm2以上6 kgf/cm2以下", "判定方法中，放水量應在350 l/min以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02346', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，電信機械室或總機室，樓地板面積為五百平方公尺， 可選擇設置下列何種設備？', '["水霧滅火設備", "二氧化碳滅火設備", "泡沫滅火設備", "密閉濕式撒水滅火設備"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02347', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法」及其相關規定，防火管理制度中有關管理權人之職責，下列何者錯誤？', '["管理權有分屬時，協議製定共同消防防護計畫", "用火用電之監督管理", "應申報防火管理人之遴用與解任", "應申報消防防護計畫書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02348', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '十層以下建築物之樓層，供餐廳、咖啡館等飲食用場所使用，且未設置水霧、泡沫、二氧化碳、乾 粉等滅火設備時，樓地板面積在多少以上者，應設置自動撒水設備？', '["一百平方公尺", "三百平方公尺", "一千平方公尺", "一千五百平方公尺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02349', 'fire-eq-tech', 'fire-eq-tech-moex-101-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」第5條規定，對於「視為另一場所」之規定敘述，下列何者 有誤？', '["建築物間設有過廊，過廊有效寬度在6公尺以下", "各類場所符合「建築技術規則」以無開口且具1小時以上防火時效之牆壁、樓地板區劃分隔者", "過廊為開放式或過廊與二側建築物相連接處之開口面積在4平方公尺以下，且設具半小時以上防 火時效之防火門", "連接建築物之間距，一樓超過5公尺，二樓以上超過9公尺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a84b39629fb3", "answer_pdf_sha1": "8a52d25bbc75", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
